module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;

    always @(*) begin
        dividend = A;
        divisor = B;
        quotient = 16'b0;
        remainder = 16'b0;

        if (dividend[15:8] >= divisor) begin
            quotient[15:8] = 8'b1;
            remainder = dividend[15:8] - divisor;
        end else begin
            quotient[15:8] = 8'b0;
            remainder = dividend[15:8];
        end

        result = {remainder, dividend[7:0]};
    end

    assign odd = remainder;

endmodule
